 1	import * as React from 'react';
 2	import {
 3	  Button,
 4	  ButtonVariant,
 5	  Toolbar,
 6	  ToolbarGroup,
 7	  ToolbarItem,
 8	  Tooltip,
 9	  TooltipPosition
10	} from '@patternfly/react-core';
11	import { connect } from 'react-redux';
12	import { KialiAppState } from '../../../store/Store';
13	import { TourStop } from 'components/Tour/TourStop';
14	import { KialiIcon } from 'config/KialiIcon';
15	import { kialiStyle } from 'styles/StyleUtils';
16	import { MeshTarget } from 'types/Mesh';
17	import { Controller } from '@patternfly/react-topology';
18	import { MeshFind } from './MeshFind';
19	import { MeshTourStops } from '../MeshHelpTour';
20	import { MeshReset } from './MeshReset';
21	import { TimeDurationComponent } from 'components/Time/TimeDurationComponent';
22	import { useKialiTranslation } from 'utils/I18nUtils';
23	import { MeshSettings } from './MeshSettings';
24	
25	type ReduxProps = {
26	  target: MeshTarget | null;
27	};
28	
29	type MeshToolbarProps = ReduxProps & {
30	  controller?: Controller;
31	  disabled: boolean;
32	  elementsChanged: boolean;
33	  onToggleHelp: () => void;
34	};
35	
36	const helpStyle = kialiStyle({
37	  marginRight: '0.5rem',
38	  alignSelf: 'center'
39	});
40	
41	export const MeshToolbarComponent: React.FC<MeshToolbarProps> = (props: MeshToolbarProps) => {
42	  const { t } = useKialiTranslation();
43	
44	  return (
45	    <>
46	      <Toolbar style={{ width: '100%' }}>
47	        <ToolbarGroup aria-label={t('mesh settings')} style={{ margin: 0, alignItems: 'flex-start' }}>
48	          <ToolbarItem style={{ margin: 0 }}>
49	            <TourStop info={MeshTourStops.Display}>
50	              <MeshSettings disabled={props.disabled} />
51	            </TourStop>
52	          </ToolbarItem>
53	
54	          <ToolbarItem>
55	            <MeshFind controller={props.controller} elementsChanged={props.elementsChanged} />
56	          </ToolbarItem>
57	
58	          <ToolbarItem style={{ marginLeft: 'auto', alignSelf: 'center' }}>
59	            <Tooltip key={'mesh-tour-help-ot'} position={TooltipPosition.right} content={t('Shortcuts and tips...')}>
60	              <TourStop info={MeshTourStops.Shortcuts}>
61	                <Button
62	                  id="mesh-tour"
63	                  variant={ButtonVariant.link}
64	                  className={helpStyle}
65	                  onClick={props.onToggleHelp}
66	                  isInline
67	                >
68	                  <KialiIcon.Help />
69	                  <span style={{ marginLeft: '5px' }}>Help</span>
70	                </Button>
71	              </TourStop>
72	            </Tooltip>
73	            <MeshReset />
74	          </ToolbarItem>
75	          <ToolbarItem>
76	            <TourStop info={MeshTourStops.TimeRange}>
77	              <TimeDurationComponent id="mesh_time_range" disabled={props.disabled} supportsReplay={false} />
78	            </TourStop>
79	          </ToolbarItem>
80	        </ToolbarGroup>
81	      </Toolbar>
82	    </>
83	  );
84	};
85	
86	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
87	  target: state.mesh.target
88	});
89	
90	export const MeshToolbar = connect(mapStateToProps)(MeshToolbarComponent);

